T_a = 25

T_l = T_a * rep(1, length(P_x_l)); #in [C] -- assuming leaf temperature equals air temperature
satur_mol_fract_air = (-0.0043 + 0.01 * exp(0.0511 * T_a)); #saturated mole fraction of vapor in air [kPa]
